class OrderPriority implements Comparable<OrderPriority> {
    private String name;

    public OrderPriority(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }

    @Override
    public int compareTo(OrderPriority other) {
        // Assuming "high" is the highest priority and "rush" is the lowest priority
        if (this.name.equals("high")) {
            return -1; // "high" comes before "rush"
        } else if (other.getName().equals("high")) {
            return 1; // "rush" comes after "high"
        } else {
            return this.name.compareTo(other.getName()); // Compare by name
        }
    }

